<style>
.sell-screen-v3{--bg:#0a0e14;--bg2:#111820;--bg3:#18202b;--bg4:#1e2838;--border:#253042;--border2:#2e3d54;--blue:#28bcee;--blue-dim:rgba(40,188,238,.12);--gold:#f9b51c;--gold-dim:rgba(249,181,28,.13);--green:#3ecf8e;--green-dim:rgba(62,207,142,.12);--red:#f87171;--red-dim:rgba(248,113,113,.1);--purple:#a78bfa;--orange:#fb923c;--text:#e6edf3;--text2:#8b949e;--text3:#4d5566;--tile-bg:var(--bg3);--tile-active-bg:var(--blue);--tile-active-text:#fff;--card-bg:var(--bg3);--card-shadow:none;--card-hover-shadow:0 4px 16px rgba(0,0,0,.3);--modal-backdrop:rgba(0,0,0,.7);--order-btn-bg:linear-gradient(135deg,var(--gold),#c98310);--order-btn-text:#1a0f00;--nav-bg:var(--bg2);--bills-bg:var(--bg2);--input-focus-shadow:none;display:flex;flex-direction:column;height:calc(100vh - 84px);min-height:720px;overflow:hidden;background:var(--bg);color:var(--text);font-family:'DM Sans',system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;border:1px solid var(--border);border-radius:18px}
