.sell-screen-v3 .product-area{flex:1;overflow-y:auto;padding:16px;scrollbar-width:thin;scrollbar-color:var(--border2) transparent;background:var(--bg)}.sell-screen-v3 .product-area::-webkit-scrollbar{width:4px}.sell-screen-v3 .product-area::-webkit-scrollbar-thumb{background:var(--border2);border-radius:3px}.sell-screen-v3 .cat-section{margin-bottom:20px}.sell-screen-v3 .cat-section[hidden]{display:none}.sell-screen-v3 .cat-header{display:flex;align-items:center;gap:10px;margin-bottom:14px;padding:0 4px}.sell-screen-v3 .cat-title{font-family:'Syne','DM Sans',sans-serif;font-size:11px;font-weight:800;color:var(--text3);text-transform:uppercase;letter-spacing:.08em;padding-left:10px;border-left:3px solid var(--blue)}.sell-screen-v3 .cat-count{font-size:10px;color:var(--text2);background:var(--bg3);padding:3px 10px;border-radius:20px;font-weight:700;font-family:'IBM Plex Mono','Space Mono',monospace}
.sell-screen-v3 .prod-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:10px}.sell-screen-v3 .prod{background:var(--card-bg);border:1px solid var(--border);border-radius:16px;padding:16px 14px;cursor:pointer;transition:all .2s;position:relative;overflow:hidden;display:flex;flex-direction:column;align-items:center;text-align:center;min-height:140px;user-select:none;box-shadow:var(--card-shadow);color:var(--text)}.sell-screen-v3 .prod:hover{border-color:var(--blue);transform:translateY(-3px);box-shadow:var(--card-hover-shadow)}.sell-screen-v3 .prod:active{transform:scale(.96);transition:transform .1s}.sell-screen-v3 .prod-emoji{font-size:32px;margin-bottom:6px;display:block;line-height:1}.sell-screen-v3 .prod-name{font-size:13px;font-weight:700;color:var(--text);line-height:1.25;margin-bottom:4px;word-break:break-word}.sell-screen-v3 .prod-price{font-size:18px;font-weight:800;color:var(--blue);font-family:'IBM Plex Mono','Space Mono',monospace;margin-top:auto;padding-top:8px}.sell-screen-v3 .prod-stock{font-size:10px;padding:2px 7px;border-radius:6px;position:absolute;top:8px;right:8px;font-weight:700}.sell-screen-v3 .ps-ok{background:rgba(5,150,105,.12);color:var(--green)}.sell-screen-v3 .ps-low{background:rgba(220,38,38,.12);color:var(--red);animation:pulseStock 2s ease-in-out infinite}.sell-screen-v3 .prod-station{font-size:9px;font-weight:800;padding:2px 8px;border-radius:10px;position:absolute;top:8px;left:8px;letter-spacing:.04em}.sell-screen-v3 .pb-kitchen{background:rgba(245,166,35,.12);color:var(--gold)}.sell-screen-v3 .pb-bar{background:rgba(40,188,238,.12);color:var(--blue)}.sell-screen-v3 .pb-cold{background:rgba(62,207,142,.12);color:var(--green)}
