.sell-screen-v3 .pay-area{padding:16px;border-top:1px solid var(--border);flex-shrink:0;background:var(--bg3)}.sell-screen-v3 .pay-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px}.sell-screen-v3 .pay-btn{padding:14px 4px;border-radius:12px;font-size:13px;font-weight:700;cursor:pointer;border:none;display:flex;align-items:center;justify-content:center;gap:6px;transition:all .2s;user-select:none;letter-spacing:.01em}.sell-screen-v3 .pay-btn:hover{transform:translateY(-2px);box-shadow:0 4px 12px rgba(0,0,0,.1)}.sell-screen-v3 .pay-btn:active{transform:scale(.96)}.sell-screen-v3 .pb-mpesa{background:linear-gradient(135deg,#00c264,#00904a);color:#fff}.sell-screen-v3 .pb-cash{background:linear-gradient(135deg,var(--blue),#1a7fd4);color:#fff}.sell-screen-v3 .pb-card{background:rgba(167,139,250,.15);color:var(--purple);border:1.5px solid rgba(124,58,237,.25)}.sell-screen-v3 .pb-credit{background:var(--gold-dim);color:var(--gold);border:1.5px solid rgba(217,119,6,.25)}.sell-screen-v3 .action-row{display:flex;gap:6px;margin-bottom:10px}.sell-screen-v3 .act-btn{flex:1;padding:10px 4px;border-radius:10px;border:1px solid var(--border);background:var(--card-bg);color:var(--text2);font-size:12px;font-weight:600;cursor:pointer;transition:all .2s;display:flex;align-items:center;justify-content:center;gap:4px;user-select:none}.sell-screen-v3 .act-btn:hover{background:var(--bg3);color:var(--text);border-color:var(--text3)}.sell-screen-v3 .kitchen-btn{width:100%;padding:18px;border-radius:14px;border:none;background:var(--order-btn-bg);color:var(--order-btn-text);font-size:15px;font-weight:700;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:8px;transition:all .2s;font-family:'Syne','DM Sans',sans-serif;letter-spacing:.02em;user-select:none;box-shadow:0 4px 16px rgba(0,0,0,.15)}.sell-screen-v3 .kitchen-btn:hover{filter:brightness(1.15);transform:translateY(-2px);box-shadow:0 8px 24px rgba(0,0,0,.2)}.sell-screen-v3 .kitchen-btn:active