-gold);color:#1a0f00;font-weight:800}.sell-screen-v3 .chip-row{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:12px}.sell-screen-v3 .chip{padding:6px 12px;border-radius:8px;font-size:12px;background:var(--bg3);border:1.5px solid var(--border);color:var(--text2);cursor:pointer;transition:all .15s;font-weight:600}.sell-screen-v3 .chip:hover{background:var(--blue-dim);color:var(--blue);border-color:rgba(40,188,238,.25)}.sell-screen-v3 .split-ways{display:flex;align-items:center;gap:14px;margin-bottom:14px}.sell-screen-v3 .split-n{font-size:24px;font-weight:700;font-family:'IBM Plex Mono','Space Mono',monospace;color:var(--blue);min-width:30px;text-align:center}
